const faqItems=document.querySelectorAll(".faq__item");faqItems.forEach((e=>{const t=e.querySelector(".faq__question"),s=e.querySelector(".faq__answer"),a=e.querySelector(".faq__answer-text");t.addEventListener("click",(()=>{const t=e.classList.contains("faq__item--open");faqItems.forEach((e=>{e.classList.remove("faq__item--open"),e.querySelector(".faq__answer").style.height="0px"})),t||(e.classList.add("faq__item--open"),s.style.height=a.offsetHeight+"px")}))}));